/** Lookup map of locale code → autonym. */
export const LOCALE_AUTONYMS: ReadonlyMap<string, string> = new Map(LOCALE_AUTONYMS_DATA);

/**
 * Get the autonym for a locale code.
 * Returns the code itself if no autonym is found.
 */
export function getLocaleAutonym(localeCode: string): string {
  const autonym = LOCALE_AUTONYMS.get(localeCode);
  if (autonym) return autonym;

  // Normalize separator and try again
  const normalized = localeCode.includes('_') ? localeCode.replace(/_/g, '-') : localeCode.replace(/-/g, '_');
  const normalizedMatch = LOCALE_AUTONYMS.get(normalized);
  if (normalizedMatch) return normalizedMatch;

  // Language subtag fallback
  const lang = localeCode.split(/[-_]/)[0];
  if (lang !== localeCode) {
    const langMatch = LOCALE_AUTONYMS.get(lang);
    if (langMatch) return langMatch;
  }

  return localeCode;
}
